actionCellButton.customFunction:
// ThingsBoard PE - Widget Sub-Clientes y Notificaciones
// Para: Action cell button en tabla de customers
// Muestra sub-clientes del customer seleccionado y permite gestionar
// el atributo notifyChild (controla si reciben email de vencimiento).

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));
let entityGroupService = $injector.get(widgetContext.servicesMap.get('entityGroupService'));
let customerService = $injector.get(widgetContext.servicesMap.get('customerService'));

const ABONADOS_GROUP_NAME = 'Abonados';

openSubClientsDialog();

function openSubClientsDialog() {
    customDialog.customDialog(htmlTemplate, SubClientsController).subscribe();
}

function SubClientsController(instance) {
    let vm = instance;

    // ── Info del customer (padre) ──
    vm.customerId = entityId;
    vm.customerName = entityName;

    // ── Estado ──
    vm.loading = true;
    vm.progressMessage = '';
    vm.subClients = [];         // [{ id, name, email, hasSubscription, expiration, plan, notifyChild }]
    vm.hasSubClients = false;

    // ── Jerarquía ──
    vm.isChildCustomer = false;      // true si tiene parentCustomerId
    vm.parentCustomerName = '';       // nombre del padre (solo si es hijo)
    vm.parentCustomerIdValue = null;  // id del padre (solo si es hijo)

    // ── Cache de grupos del padre (evita doble llamada API) ──
    let _parentOwnedGroups = null;

    // ── Inicializar ──
    loadAll();

    vm.cancel = function () {
        vm.dialogRef.close(null);
    };

    // ── Carga principal ──
    function loadAll() {
        vm.loading = true;
        vm.progressMessage = 'Cargando información...';

        // 1) Detectar si es hijo y resolver grupo de notificaciones
        resolveCustomerHierarchy().then(function () {
            // 2) Cargar sub-clientes
            return loadSubClients();
        }).then(function () {
            vm.loading = false;
            vm.progressMessage = '';
        }).catch(function (err) {
            console.error('Error cargando datos:', err);
            vm.loading = false;
            vm.progressMessage = '';
        });
    }

    // ── Detectar jerarquía del customer ──
    function resolveCustomerHierarchy() {
        return new Promise(function (resolve) {
            customerService.getCustomer(vm.customerId.id).subscribe(
                function (customer) {
                    if (customer.parentCustomerId && customer.parentCustomerId.id) {
                        vm.isChildCustomer = true;
                        vm.parentCustomerIdValue = customer.parentCustomerId.id;
                        // Obtener nombre del padre
                        customerService.getCustomer(vm.parentCustomerIdValue).subscribe(
                            function (parent) {
                                vm.parentCustomerName = parent.title || parent.name || vm.parentCustomerIdValue;
                                resolve();
                            },
                            function () {
                                vm.parentCustomerName = vm.parentCustomerIdValue;
                                resolve();
                            }
                        );
                    } else {
                        vm.isChildCustomer = false;
                        resolve();
                    }
                },
                function () { resolve(); }
            );
        });
    }

    function getParentOwnedGroups() {
        if (_parentOwnedGroups !== null) {
            return Promise.resolve(_parentOwnedGroups);
        }
        return new Promise(function (resolve) {
            entityGroupService.getEntityGroupsByOwnerId('CUSTOMER', vm.customerId.id, 'CUSTOMER').subscribe(
                function (groups) {
                    _parentOwnedGroups = groups || [];
                    resolve(_parentOwnedGroups);
                },
                function () {
                    _parentOwnedGroups = [];
                    resolve(_parentOwnedGroups);
                }
            );
        });
    }

    // ── Cargar sub-clientes del customer (vía grupo "All" del padre) ──
    function loadSubClients() {
        return getParentOwnedGroups().then(function (groups) {
            let allGroup = groups.find(function (g) { return g.name === 'All'; });
            if (!allGroup) {
                vm.hasSubClients = false;
                return;
            }

            return new Promise(function (resolve) {
                let url = '/api/entityGroup/' + allGroup.id.id + '/entities?pageSize=100&page=0';
                widgetContext.http.get(url).subscribe(
                    function (response) {
                        let customers = response.data || [];
                        vm.hasSubClients = customers.length > 0;

                        if (customers.length === 0) {
                            resolve();
                            return;
                        }

                        // Cargar atributos de suscripción para cada sub-cliente
                        let attrPromises = customers.map(function (c) {
                            return loadSubscriptionAttrs(c);
                        });

                        Promise.all(attrPromises).then(function (results) {
                            vm.subClients = results;
                            resolve();
                        }).catch(function () {
                            // Fallback: al menos mostrar los customers sin info de suscripción
                            vm.subClients = customers.map(function (c) {
                                return {
                                    id: c.id.id,
                                    name: c.title || c.name || c.id.id,
                                    email: c.email || '—',
                                    hasSubscription: false,
                                    expiration: '—',
                                    plan: '—',
                                    notifyChild: false
                                };
                            });
                            resolve();
                        });
                    },
                    function () {
                        vm.hasSubClients = false;
                        resolve();
                    }
                );
            });
        });
    }

    // ── Cargar atributos de suscripción de un customer ──
    function loadSubscriptionAttrs(customer) {
        return new Promise(function (resolve) {
            let cId = { id: customer.id.id, entityType: 'CUSTOMER' };
            attributeService.getEntityAttributes(cId, 'SERVER_SCOPE',
                ['subscription', 'subscriptionExpiration', 'plan', 'notifyChild']).subscribe(
                    function (attrs) {
                        let subAttr = attrs.find(function (a) { return a.key === 'subscription'; });
                        let expAttr = attrs.find(function (a) { return a.key === 'subscriptionExpiration'; });
                        let planAttr = attrs.find(function (a) { return a.key === 'plan'; });
                        let notifyAttr = attrs.find(function (a) { return a.key === 'notifyChild'; });

                        let hasSub = !!(subAttr && subAttr.value && expAttr && expAttr.value);
                        let isExpired = false;
                        if (hasSub) {
                            let parsed = parseDate(expAttr.value);
                            if (parsed && !isNaN(parsed.getTime())) {
                                let now = new Date();
                                now.setHours(0, 0, 0, 0);
                                isExpired = parsed.getTime() < now.getTime();
                            }
                        }

                        // notifyChild como dato informativo (se gestiona desde Abono)
                        let notify = notifyAttr && notifyAttr.value === 'true';

                        resolve({
                            id: customer.id.id,
                            name: customer.title || customer.name || customer.id.id,
                            email: customer.email || '—',
                            hasSubscription: hasSub,
                            isExpired: isExpired,
                            expiration: expAttr && expAttr.value ? expAttr.value : '—',
                            plan: planAttr && planAttr.value ? planAttr.value : '—',
                            notifyChild: notify
                        });
                    },
                    function () {
                        resolve({
                            id: customer.id.id,
                            name: customer.title || customer.name || customer.id.id,
                            email: customer.email || '—',
                            hasSubscription: false,
                            isExpired: false,
                            expiration: '—',
                            plan: '—',
                            notifyChild: false
                        });
                    }
                );
        });
    }

    // ── Parsear DD/MM/YYYY ──
    function parseDate(dateStr) {
        if (!dateStr) return null;
        let parts = dateStr.split('/');
        if (parts.length !== 3) return null;
        return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    }
}

