actionCellButton.customFunction:
// ThingsBoard PE - Widget Due Notification
// Envía notificación de vencimiento seteando customerAction = 'dueDate'
// Si el customer tiene un padre, guarda parentNotificationEmail en el HIJO
// para que la rule chain envíe el email al padre sin tocar sus atributos.
// Al padre se le notifica SIEMPRE. Al hijo se le notifica según atributo notifyChild.

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));
let customerService = $injector.get(widgetContext.servicesMap.get('customerService'));

openDueNotificationDialog();

function openDueNotificationDialog() {
    customDialog.customDialog(htmlTemplate, DueNotificationController).subscribe();
}

function DueNotificationController(instance) {
    let vm = instance;

    // Info del customer
    vm.customerId = entityId;
    vm.customerName = entityName;

    // Estado
    vm.loading = true;
    vm.sending = false;
    vm.hasSubscription = false;
    vm.subscriptionExpiration = '';
    vm.subscriptionPlan = '';
    vm.isExpired = false;
    vm.daysRemaining = null;

    // Customer padre
    vm.parentCustomer = null;  // { id, name, email }
    vm.loadingParent = false;

    // Verificaciones
    vm.isChildCustomer = false;          // tiene parentCustomerId

    // Toggles de notificación
    vm.notifyChild = true;               // se setea según atributo notifyChild al cargar
    vm.originalNotifyChild = true;       // valor original del atributo (para revertir después de enviar)

    // Cargar atributos del customer, buscar padre, y leer notifyChild
    loadAttributes();
    loadParentCustomer();
    loadNotifyChildAttr();

    vm.cancel = function () {
        vm.dialogRef.close(null);
    };

    // Enviar notificación:
    // - parentNotificationEmail: siempre se incluye si hay padre con email
    // - customerAction = 'dueDate' dispara el flujo vía root chain
    // - notifyChild controla si el hijo recibe email o no
    vm.sendNotification = function () {
        vm.sending = true;

        let attrsToSave = [];

        // parentNotificationEmail: siempre si hay padre con email (al padre se le notifica siempre)
        if (vm.parentCustomer && vm.parentCustomer.email) {
            attrsToSave.push({ key: 'parentNotificationEmail', value: vm.parentCustomer.email });
        } else {
            attrsToSave.push({ key: 'parentNotificationEmail', value: '' });
        }

        // notifyChild: envío manual siempre envía el email.
        // Para clientes sin hijos → siempre 'true'
        // Para hijos → según checkbox (permite excluir al hijo de este envío)
        let notifyValue = (!vm.isChildCustomer || vm.notifyChild) ? 'true' : 'false';
        attrsToSave.push({ key: 'notifyChild', value: notifyValue });

        // Flag que dispara el flujo post-date en la rule chain
        attrsToSave.push({ key: 'customerAction', value: 'dueDate' });

        attributeService.saveEntityAttributes(vm.customerId, 'SERVER_SCOPE', attrsToSave).subscribe(
            function () {
                // Siempre revertir notifyChild al valor original
                // (el envío manual no cambia la preferencia persistente)
                attributeService.saveEntityAttributes(vm.customerId, 'SERVER_SCOPE',
                    [{ key: 'notifyChild', value: vm.originalNotifyChild ? 'true' : 'false' }]
                ).subscribe();
                vm.sending = false;
                let msg = vm.parentCustomer
                    ? 'Notificación enviada al cliente y al padre (' + vm.parentCustomer.name + ')'
                    : 'Notificación de vencimiento enviada';
                widgetContext.showSuccessToast(msg);
                widgetContext.updateAliases();
                vm.dialogRef.close(null);
            },
            function (error) {
                vm.sending = false;
                widgetContext.showErrorToast('Error: ' + (error.message || JSON.stringify(error)));
                console.error('Error enviando notificación:', error);
            }
        );
    };

    function loadAttributes() {
        vm.loading = true;
        attributeService.getEntityAttributes(vm.customerId, 'SERVER_SCOPE',
            ['subscription', 'subscriptionExpiration', 'subscriptionExpirationTs', 'plan', 'deviceQty']).subscribe(
                function (attributes) {
                    let subscriptionAttr = attributes.find(a => a.key === 'subscription');
                    let expirationAttr = attributes.find(a => a.key === 'subscriptionExpiration');
                    let planAttr = attributes.find(a => a.key === 'plan');

                    if (subscriptionAttr && subscriptionAttr.value &&
                        expirationAttr && expirationAttr.value) {
                        vm.hasSubscription = true;
                        vm.subscriptionExpiration = expirationAttr.value;
                        vm.subscriptionPlan = planAttr && planAttr.value ? planAttr.value : '—';

                        // Calcular días restantes
                        let parsed = parseDate(expirationAttr.value);
                        if (parsed && !isNaN(parsed.getTime())) {
                            let now = new Date();
                            now.setHours(0, 0, 0, 0);
                            let diffMs = parsed.getTime() - now.getTime();
                            vm.daysRemaining = Math.round(diffMs / 86400000);
                            vm.isExpired = vm.daysRemaining < 0;
                        }
                    } else {
                        vm.hasSubscription = false;
                    }
                    vm.loading = false;
                },
                function (error) {
                    console.error('Error cargando atributos:', error);
                    vm.hasSubscription = false;
                    vm.loading = false;
                }
            );
    }

    // Buscar customer padre y leer atributo notifyChild
    function loadParentCustomer() {
        vm.loadingParent = true;

        customerService.getCustomer(vm.customerId.id).subscribe(
            function (customer) {
                if (customer && customer.parentCustomerId && customer.parentCustomerId.id) {
                    vm.isChildCustomer = true;
                    let parentId = customer.parentCustomerId.id;

                    getParentInfo(parentId).then(function () {
                        vm.loadingParent = false;
                    });
                } else {
                    vm.isChildCustomer = false;
                    vm.parentCustomer = null;
                    vm.loadingParent = false;
                }
            },
            function (error) {
                console.error('Error obteniendo customer:', error);
                vm.parentCustomer = null;
                vm.loadingParent = false;
            }
        );
    }

    // Obtener nombre y email del padre
    function getParentInfo(parentId) {
        return new Promise(function (resolve) {
            customerService.getCustomer(parentId).subscribe(
                function (parent) {
                    vm.parentCustomer = {
                        id: parentId,
                        name: parent.title || parent.name || parent.id.id,
                        email: parent.email || null
                    };
                    resolve();
                },
                function () {
                    vm.parentCustomer = null;
                    resolve();
                }
            );
        });
    }

    // Leer atributo notifyChild del hijo
    function loadNotifyChildAttr() {
        return new Promise(function (resolve) {
            attributeService.getEntityAttributes(vm.customerId, 'SERVER_SCOPE', ['notifyChild']).subscribe(
                function (attrs) {
                    let attr = attrs.find(function (a) { return a.key === 'notifyChild'; });
                    // Si existe el atributo, usar su valor; si no existe, default true
                    let val = attr ? attr.value === 'true' : true;
                    vm.notifyChild = val;
                    vm.originalNotifyChild = val;
                    resolve();
                },
                function () {
                    vm.notifyChild = true;
                    vm.originalNotifyChild = true;
                    resolve();
                }
            );
        });
    }

    // Parsear DD/MM/YYYY a Date
    function parseDate(dateStr) {
        if (!dateStr) return null;
        let parts = dateStr.split('/');
        if (parts.length !== 3) return null;
        return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    }
}

