actionCellButton.customFunction:
// ThingsBoard PE - Widget Habilitar/Deshabilitar Usuarios de un Customer
// Para: Action cell button en tabla de customers

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));

openToggleUsersDialog();

function openToggleUsersDialog() {
    customDialog.customDialog(htmlTemplate, ToggleUsersController).subscribe();
}

function ToggleUsersController(instance) {
    let vm = instance;
    let customerId = entityId.id;

    vm.customerName = entityName;
    vm.processing = false;
    vm.progressMessage = '';
    vm.users = [];
    vm.loading = true;
    vm.enabledCount = 0;
    vm.disabledCount = 0;
    vm.inactiveCount = 0;

    // ── Estado de confirmación ──
    // { type: 'enable'|'disable', title, message, icon, confirmLabel, action: fn }
    vm.confirmAction = null;

    // Cargar usuarios al abrir
    loadUsers();

    vm.cancel = function () {
        vm.dialogRef.close(null);
    };

    // ── Confirmación inline ──
    vm.cancelConfirm = function () {
        vm.confirmAction = null;
    };

    vm.executeConfirm = function () {
        if (vm.confirmAction && vm.confirmAction.action) {
            vm.confirmAction.action();
        }
        vm.confirmAction = null;
    };

    // ── Acciones con confirmación ──
    vm.confirmDisableAll = function () {
        vm.confirmAction = {
            type: 'disable',
            icon: 'person_off',
            title: 'Deshabilitar todos los usuarios',
            message: '¿Estás seguro de deshabilitar los ' + vm.enabledCount + ' usuario(s) habilitados de "' + vm.customerName + '"? No podrán acceder a la plataforma.',
            confirmLabel: 'Deshabilitar todos',
            action: function () {
                vm.processing = true;
                toggleUsers(false).then(function (count) {
                    vm.processing = false;
                    widgetContext.showSuccessToast(
                        count + ' usuario(s) deshabilitado(s) de "' + vm.customerName + '"'
                    );
                    vm.dialogRef.close(null);
                }).catch(function (error) {
                    vm.processing = false;
                    widgetContext.showErrorToast('Error: ' + (error.message || JSON.stringify(error)));
                });
            }
        };
    };

    vm.confirmEnableAll = function () {
        vm.confirmAction = {
            type: 'enable',
            icon: 'person',
            title: 'Habilitar todos los usuarios',
            message: '¿Estás seguro de habilitar los ' + vm.disabledCount + ' usuario(s) deshabilitados de "' + vm.customerName + '"? Podrán acceder nuevamente a la plataforma.',
            confirmLabel: 'Habilitar todos',
            action: function () {
                vm.processing = true;
                toggleUsers(true).then(function (count) {
                    vm.processing = false;
                    widgetContext.showSuccessToast(
                        count + ' usuario(s) habilitado(s) de "' + vm.customerName + '"'
                    );
                    vm.dialogRef.close(null);
                }).catch(function (error) {
                    vm.processing = false;
                    widgetContext.showErrorToast('Error: ' + (error.message || JSON.stringify(error)));
                });
            }
        };
    };

    vm.toggleUser = function (user) {
        if (!user._activated || user._activated === false) return;
        let newState = !user._enabled;
        vm.confirmAction = {
            type: newState ? 'enable' : 'disable',
            icon: newState ? 'person' : 'person_off',
            title: (newState ? 'Habilitar' : 'Deshabilitar') + ' usuario',
            message: '¿Estás seguro de ' + (newState ? 'habilitar' : 'deshabilitar') + ' a ' + user.email + '?',
            confirmLabel: newState ? 'Habilitar' : 'Deshabilitar',
            action: function () {
                vm.processing = true;
                vm.progressMessage = (newState ? 'Habilitando' : 'Deshabilitando') + ' ' + user.email + '...';
                widgetContext.http.post(
                    '/api/user/' + user.id.id + '/userCredentialsEnabled?userCredentialsEnabled=' + newState,
                    null
                ).toPromise().then(function () {
                    user._enabled = newState;
                    updateCounts();
                    vm.processing = false;
                    vm.progressMessage = '';
                }).catch(function (e) {
                    vm.processing = false;
                    vm.progressMessage = '';
                    widgetContext.showErrorToast('Error: ' + (e.error ? e.error.message : JSON.stringify(e)));
                });
            }
        };
    };

    async function loadUsers() {
        try {
            let response = await widgetContext.http.get(
                '/api/customer/' + customerId + '/users?pageSize=1000&page=0'
            ).toPromise();

            vm.users = response.data || [];

            for (let user of vm.users) {
                try {
                    let fullUser = await widgetContext.http.get(
                        '/api/user/' + user.id.id
                    ).toPromise();
                    let info = fullUser.additionalInfo || {};

                    // Si userActivated es explícitamente false, el usuario no activó su cuenta
                    if (info.userActivated === false) {
                        user._activated = false;
                        user._enabled = false;
                        continue;
                    }

                    user._activated = true;
                    user._enabled = info.userCredentialsEnabled !== false;
                } catch (e) {
                    // Si no puede obtener info, asumir activado y habilitado
                    user._activated = true;
                    user._enabled = true;
                }
            }
            updateCounts();
            vm.loading = false;
        } catch (error) {
            console.error('Error cargando usuarios:', error);
            vm.users = [];
            vm.loading = false;
        }
    }

    function updateCounts() {
        let activated = vm.users.filter(function (u) { return u._activated !== false; });
        vm.enabledCount = activated.filter(function (u) { return u._enabled === true; }).length;
        vm.disabledCount = activated.filter(function (u) { return u._enabled === false; }).length;
        vm.inactiveCount = vm.users.filter(function (u) { return u._activated === false; }).length;
    }

    async function toggleUsers(enable) {
        let count = 0;
        let label = enable ? 'Habilitando' : 'Deshabilitando';
        // Filtrar solo usuarios activados cuyo estado difiere del deseado
        let targets = vm.users.filter(function (u) {
            return u._activated === true && u._enabled !== enable;
        });

        for (let i = 0; i < targets.length; i++) {
            let user = targets[i];
            vm.progressMessage = label + ' usuario ' + (i + 1) + ' de ' + targets.length + '...';
            try {
                await widgetContext.http.post(
                    '/api/user/' + user.id.id + '/userCredentialsEnabled?userCredentialsEnabled=' + enable,
                    null
                ).toPromise();
                user._enabled = enable;
                count++;
            } catch (e) {
                // Solo logear si es un error inesperado
                if (e.status !== 400) {
                    console.error('Error con usuario ' + user.email + ':', e);
                }
            }
        }
        updateCounts();
        return count;
    }
}

