actionCellButton.customFunction:
// ThingsBoard PE - Widget Opciones Avanzadas del Customer
// Para: Action cell button en tabla de customers

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));

openAdvanceOptionsDialog();

function openAdvanceOptionsDialog() {
  customDialog.customDialog(htmlTemplate, AdvanceOptionsController).subscribe();
}

function AdvanceOptionsController(instance) {
  let vm = instance;
  let customerId = entityId.id;

  vm.customerName = entityName;
  vm.loading = true;
  vm.saving = false;

  // Opciones disponibles — agregar nuevas entradas aquí para escalar
  vm.options = [
    {
      key: 'report_interval',
      label: 'Intervalo de reporte',
      description: 'Permite modificar la frecuencia de envío de datos del dispositivo',
      icon: 'schedule',
      value: false,
    },
  ];

  loadOptions();

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    vm.saving = true;

    let json = {};
    vm.options.forEach(function (opt) {
      json[opt.key] = opt.value;
    });

    let entity = { id: customerId, entityType: 'CUSTOMER' };
    attributeService
      .saveEntityAttributes(entity, 'SERVER_SCOPE', [{ key: 'advanceOptions', value: json }])
      .subscribe(
        function () {
          vm.saving = false;
          widgetContext.showSuccessToast('Opciones actualizadas para "' + vm.customerName + '"');
          vm.dialogRef.close(true);
        },
        function (error) {
          vm.saving = false;
          widgetContext.showErrorToast(
            'Error guardando opciones: ' + (error.message || JSON.stringify(error)),
          );
        },
      );
  };

  function loadOptions() {
    let entity = { id: customerId, entityType: 'CUSTOMER' };
    attributeService
      .getEntityAttributes(entity, 'SERVER_SCOPE', ['advanceOptions'])
      .subscribe(
        function (attrs) {
          if (attrs && attrs.length > 0) {
            let raw = attrs[0].value;
            let current = typeof raw === 'string' ? JSON.parse(raw) : raw;
            vm.options.forEach(function (opt) {
              if (current.hasOwnProperty(opt.key)) {
                opt.value = current[opt.key] === true;
              }
            });
          }
          vm.loading = false;
        },
        function () {
          vm.loading = false;
        },
      );
  }
}

