actionCellButton.customFunction:
// ThingsBoard PE - Widget Eliminar Customer (Limpieza Completa)
// Para: Action cell button en tabla de customers
//
// Limpieza Chirpstack/Integration TB se delega a la rule chain ChirpstackProxyV2
// (rama ENTITY_DELETED). Este widget solo:
// - Lee atributos del customer y muestra checkboxes de cleanup.
// - Antes del DELETE final, mergea flags + IDs en customer.additionalInfo via PUT
//   /api/customer para que ENTITY_DELETED llegue a la rule chain con todo lo
//   necesario en msg.additionalInfo.
// - Hace DELETE customer (la rule chain corre fire-and-forget en background).

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let customerService = $injector.get(widgetContext.servicesMap.get('customerService'));

const NULL_UUID = '13814000-1dd2-11b2-8080-808080808080';

openDeleteCustomerDialog();

function openDeleteCustomerDialog() {
    customDialog.customDialog(htmlTemplate, DeleteCustomerController).subscribe();
}

function DeleteCustomerController(instance) {
    let vm = instance;
    let customerId = entityId.id;

    vm.customerName = entityName;
    vm.deleting = false;
    vm.loadingContext = true;
    vm.progressMessage = '';
    vm.confirmationText = '';
    vm.errorMessage = '';

    vm.isSubClient = false;
    vm.tbIntegrationId = null;
    vm.chirpstackTenantId = null;
    vm.chirpstackApplicationId = null;

    vm.hasTbIntegration = false;
    vm.hasCsApplication = false;
    vm.hasCsTenant = false;

    vm.deleteTbIntegration = true;
    vm.deleteCsApplication = true;
    vm.deleteCsTenant = true;

    loadContext().then(function () {
        vm.loadingContext = false;
    }).catch(function () {
        vm.loadingContext = false;
    });

    vm.isConfirmationValid = function () {
        return vm.confirmationText === vm.customerName;
    };

    vm.cancel = function () {
        vm.dialogRef.close(null);
    };

    vm.confirmDelete = function () {
        vm.deleting = true;
        vm.errorMessage = '';
        vm.progressMessage = 'Iniciando eliminación...';

        deleteCustomerComplete().then(function (cleanupTriggered) {
            vm.deleting = false;
            if (cleanupTriggered) {
                widgetContext.showSuccessToast(
                    'Customer "' + vm.customerName + '" eliminado. '
                    + 'Limpieza Chirpstack en proceso (puede tardar unos segundos).'
                );
            } else {
                widgetContext.showSuccessToast(
                    'Customer "' + vm.customerName + '" eliminado exitosamente'
                );
            }
            widgetContext.updateAliases();
            vm.dialogRef.close(null);
        }).catch(function (error) {
            vm.deleting = false;
            let msg = (error && error.message) ? error.message
                    : (typeof error === 'string') ? error
                    : JSON.stringify(error);
            vm.errorMessage = msg;
            widgetContext.showErrorToast('Error: ' + msg);
            console.error('Error eliminando customer:', error);
        });
    };

    async function loadContext() {
        try {
            let customer = await widgetContext.http.get('/api/customer/' + customerId).toPromise();
            let parentId = customer && customer.parentCustomerId && customer.parentCustomerId.id;
            vm.isSubClient = !!parentId && parentId !== NULL_UUID;

            let attrsUrl = '/api/plugins/telemetry/CUSTOMER/' + customerId
                         + '/values/attributes/SERVER_SCOPE'
                         + '?keys=ChirpstackTenantId,ChirpstackApplicationId,TbIntegrationId';
            let attrs = await widgetContext.http.get(attrsUrl).toPromise();
            let map = {};
            (attrs || []).forEach(function (a) { map[a.key] = a.value; });

            if (map.TbIntegrationId) {
                vm.tbIntegrationId = map.TbIntegrationId;
                vm.hasTbIntegration = !vm.isSubClient;
            }
            if (map.ChirpstackApplicationId) {
                vm.chirpstackApplicationId = map.ChirpstackApplicationId;
                vm.hasCsApplication = vm.isSubClient;
            }
            if (map.ChirpstackTenantId) {
                vm.chirpstackTenantId = map.ChirpstackTenantId;
                vm.hasCsTenant = !vm.isSubClient;
            }
        } catch (e) {
            console.warn('No se pudo cargar contexto de cleanup:', e);
        }
    }

    async function deleteCustomerComplete() {
        vm.progressMessage = 'Eliminando dispositivos...';
        await deleteAllDevices(customerId);

        vm.progressMessage = 'Eliminando assets...';
        await deleteAllAssets(customerId);

        vm.progressMessage = 'Eliminando dashboards...';
        await deleteAllDashboards(customerId);

        let cleanupTriggered = false;
        let needsCleanupFlags =
               (vm.hasTbIntegration && vm.deleteTbIntegration)
            || (vm.isSubClient && vm.hasCsApplication && vm.deleteCsApplication)
            || (!vm.isSubClient && vm.hasCsTenant && vm.deleteCsTenant);

        if (needsCleanupFlags) {
            vm.progressMessage = 'Marcando limpieza Chirpstack...';
            await stageCleanupFlags(customerId);
            cleanupTriggered = true;
        }

        vm.progressMessage = 'Eliminando customer...';
        await deleteCustomer(customerId);

        return cleanupTriggered;
    }

    async function stageCleanupFlags(custId) {
        let customer = await widgetContext.http.get('/api/customer/' + custId).toPromise();
        customer.additionalInfo = customer.additionalInfo || {};

        customer.additionalInfo.deleteTbIntegration =
            !!(vm.deleteTbIntegration && vm.hasTbIntegration);
        customer.additionalInfo.deleteChirpstackApplication =
            !!(vm.isSubClient && vm.deleteCsApplication && vm.hasCsApplication);
        customer.additionalInfo.deleteChirpstackTenant =
            !!(!vm.isSubClient && vm.deleteCsTenant && vm.hasCsTenant);

        if (vm.tbIntegrationId)         customer.additionalInfo.tbIntegrationId = vm.tbIntegrationId;
        if (vm.chirpstackApplicationId) customer.additionalInfo.chirpstackApplicationId = vm.chirpstackApplicationId;
        if (vm.chirpstackTenantId)      customer.additionalInfo.chirpstackTenantId = vm.chirpstackTenantId;

        await widgetContext.http.post('/api/customer', customer).toPromise();
    }

    async function deleteAllDevices(custId) {
        try {
            let response = await widgetContext.http.get(
                '/api/customer/' + custId + '/devices?pageSize=1000&page=0'
            ).toPromise();
            let devices = response.data || [];
            for (let device of devices) {
                try { await widgetContext.http.delete('/api/device/' + device.id.id).toPromise(); }
                catch (e) { /* skip */ }
            }
        } catch (error) { /* skip */ }
    }

    async function deleteAllAssets(custId) {
        try {
            let response = await widgetContext.http.get(
                '/api/customer/' + custId + '/assets?pageSize=1000&page=0'
            ).toPromise();
            let assets = response.data || [];
            for (let asset of assets) {
                try { await widgetContext.http.delete('/api/asset/' + asset.id.id).toPromise(); }
                catch (e) { /* skip */ }
            }
        } catch (error) { /* skip */ }
    }

    async function deleteAllDashboards(custId) {
        try {
            let response = await widgetContext.http.get(
                '/api/customer/' + custId + '/dashboards?pageSize=1000&page=0'
            ).toPromise();
            let dashboards = response.data || [];
            for (let dashboard of dashboards) {
                try { await widgetContext.http.delete('/api/dashboard/' + dashboard.id.id).toPromise(); }
                catch (e) { /* skip */ }
            }
        } catch (error) { /* skip */ }
    }

    function deleteCustomer(custId) {
        return new Promise(function (resolve, reject) {
            customerService.deleteCustomer(custId).subscribe(
                function () { resolve(); },
                function (error) { reject(error); }
            );
        });
    }
}

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));

customDialog.customDialog(htmlTemplate, AccessController).subscribe();

function AccessController(instance) {
    let vm = instance;
    let customerId = entityId.id;

    vm.users = [];
    vm.dashboards = [];
    vm.selectedUser = null;
    vm.selectedDashboards = {};
    vm.accessAll = true;
    vm.loading = true;

    // Cargar usuarios y dashboards en paralelo
    Promise.all([
        widgetContext.http.get('/api/customer/' + customerId + '/users?pageSize=100&page=0').toPromise(),
        widgetContext.http.get('/api/customer/' + customerId + '/dashboards?pageSize=100&page=0').toPromise()
    ]).then(function(results) {
        vm.users = results[0].data || [];
        vm.dashboards = results[1].data || [];
        vm.loading = false;
    });

    vm.selectUser = function(user) {
        vm.selectedUser = user;
        vm.selectedDashboards = {};
        vm.accessAll = true;

        let userId = user.id.id;
        widgetContext.http.get(
            '/api/plugins/telemetry/USER/' + userId + '/values/attributes/SERVER_SCOPE'
        ).toPromise().then(function(attrs) {
            let map = {};
            (attrs || []).forEach(function(a) { map[a.key] = a.value; });

            vm.accessAll = map.dashboardAccess !== 'restricted';

            let allowed = map.allowedDashboards || [];
            allowed.forEach(function(id) { vm.selectedDashboards[id] = true; });
        });
    };

    vm.save = function() {
        if (!vm.selectedUser) return;

        let userId = vm.selectedUser.id.id;
        let payload;

        if (vm.accessAll) {
            payload = { dashboardAccess: 'all' };
        } else {
            let ids = Object.keys(vm.selectedDashboards).filter(function(id) {
                return vm.selectedDashboards[id];
            });
            payload = { dashboardAccess: 'restricted', allowedDashboards: ids };
        }

        widgetContext.http.post(
            '/api/plugins/telemetry/USER/' + userId + '/attributes/SERVER_SCOPE',
            payload
        ).toPromise().then(function() {
            widgetContext.showSuccessToast('Acceso guardado para ' + vm.selectedUser.email);
            vm.selectedUser = null;
        });
    };

    vm.cancel = function() {
        vm.dialogRef.close(null);
    };
}

