actionCellButton.customFunction:
// ─────────────────────────────────────────────────────────────────────────────
// Widget: Gestión de Acceso a Dashboards
// Tipo: Custom Action (tabla de customers, tenant admin)
// Compatible: ThingsBoard CE (sin entityGroupService ni PE features)
// Atributos que escribe en SERVER_SCOPE del USER:
//   dashboardAccess:   'all' | 'restricted'
//   allowedDashboards: JSON string de array de IDs → '["uuid1","uuid2"]'
// ─────────────────────────────────────────────────────────────────────────────

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));

openAccessDialog();

function openAccessDialog() {
    customDialog.customDialog(htmlTemplate, AccessController).subscribe();
}

function AccessController(instance) {
    let vm = instance;

    // ── Info del customer ────────────────────────────────────────────────────
    vm.customerId = entityId;       // { id: '...', entityType: 'CUSTOMER' }
    vm.customerName = entityName;

    // ── Listas ──────────────────────────────────────────────────────────────
    vm.users = [];
    vm.dashboards = [];

    // ── Selección de usuario ─────────────────────────────────────────────────
    vm.selectedUser = null;

    // ── Estado de acceso del usuario seleccionado ────────────────────────────
    vm.accessMode = 'all';          // 'all' | 'restricted'
    vm.allowedDashboardIds = [];    // IDs habilitados cuando mode = 'restricted'

    // ── Flags de carga ───────────────────────────────────────────────────────
    vm.loadingInit = true;          // Carga inicial de usuarios y dashboards
    vm.loadingAttrs = false;        // Carga de atributos del usuario seleccionado
    vm.saving = false;
    vm.saveSuccess = false;         // Flash de confirmación post-save

    // ── Errores ──────────────────────────────────────────────────────────────
    vm.initError = null;

    // ── Carga inicial ────────────────────────────────────────────────────────
    Promise.all([
        loadUsers(),
        loadDashboards()
    ]).then(function () {
        vm.loadingInit = false;
        safeApply();
    }).catch(function (err) {
        vm.loadingInit = false;
        vm.initError = 'Error al cargar datos: ' + (err.message || err);
        safeApply();
    });

    // ── Cargar usuarios del customer ─────────────────────────────────────────
    function loadUsers() {
        return new Promise(function (resolve, reject) {
            widgetContext.http.get(
                '/api/customer/' + vm.customerId.id + '/users?pageSize=200&page=0'
            ).subscribe(
                function (response) {
                    vm.users = (response.data || []).map(function (u) {
                        let displayName = '';
                        if (u.firstName || u.lastName) {
                            displayName = [u.firstName, u.lastName].filter(Boolean).join(' ');
                        } else {
                            displayName = u.email || u.id.id;
                        }
                        return {
                            id: u.id.id,
                            entityType: 'USER',
                            name: displayName,
                            email: u.email || ''
                        };
                    });
                    resolve();
                },
                function (err) {
                    reject(err);
                }
            );
        });
    }

    // ── Cargar dashboards asignados al customer ──────────────────────────────
    function loadDashboards() {
        return new Promise(function (resolve, reject) {
            widgetContext.http.get(
                '/api/customer/' + vm.customerId.id + '/dashboards?pageSize=200&page=0'
            ).subscribe(
                function (response) {
                    vm.dashboards = (response.data || [])
                        .map(function (d) {
                            return { id: d.id.id, title: d.title };
                        })
                        .sort(function (a, b) {
                            return a.title.localeCompare(b.title, 'es');
                        });
                    resolve();
                },
                function (err) {
                    reject(err);
                }
            );
        });
    }

    // ── Al seleccionar un usuario: leer sus atributos de acceso ─────────────
    vm.onUserSelected = function () {
        if (!vm.selectedUser) return;

        vm.loadingAttrs = true;
        vm.accessMode = 'all';
        vm.allowedDashboardIds = [];
        vm.saveSuccess = false;

        let userEntityId = { id: vm.selectedUser.id, entityType: 'USER' };

        attributeService.getEntityAttributes(
            userEntityId,
            'SERVER_SCOPE',
            ['dashboardAccess', 'allowedDashboards']
        ).subscribe(
            function (attrs) {
                let accessAttr  = attrs.find(function (a) { return a.key === 'dashboardAccess'; });
                let allowedAttr = attrs.find(function (a) { return a.key === 'allowedDashboards'; });

                if (accessAttr && accessAttr.value === 'restricted') {
                    vm.accessMode = 'restricted';
                    if (allowedAttr && allowedAttr.value) {
                        try {
                            let parsed = (typeof allowedAttr.value === 'string')
                                ? JSON.parse(allowedAttr.value)
                                : allowedAttr.value;
                            vm.allowedDashboardIds = Array.isArray(parsed) ? parsed : [];
                        } catch (e) {
                            vm.allowedDashboardIds = [];
                        }
                    }
                } else {
                    vm.accessMode = 'all';
                    vm.allowedDashboardIds = [];
                }

                vm.loadingAttrs = false;
                safeApply();
            },
            function (err) {
                // Si el usuario no tiene atributos (404 o array vacío), comportamiento por defecto = all
                vm.accessMode = 'all';
                vm.allowedDashboardIds = [];
                vm.loadingAttrs = false;
                safeApply();
            }
        );
    };

    // ── Cambiar modo de acceso ───────────────────────────────────────────────
    vm.setAccessMode = function (mode) {
        vm.accessMode = mode;
        if (mode === 'all') {
            vm.allowedDashboardIds = [];
        }
        vm.saveSuccess = false;
    };

    // ── Helpers de selección de dashboards ──────────────────────────────────
    vm.isDashboardSelected = function (id) {
        return vm.allowedDashboardIds.indexOf(id) !== -1;
    };

    vm.toggleDashboard = function (id) {
        let idx = vm.allowedDashboardIds.indexOf(id);
        if (idx === -1) {
            vm.allowedDashboardIds.push(id);
        } else {
            vm.allowedDashboardIds.splice(idx, 1);
        }
        vm.saveSuccess = false;
    };

    vm.selectAll = function () {
        vm.allowedDashboardIds = vm.dashboards.map(function (d) { return d.id; });
        vm.saveSuccess = false;
    };

    vm.selectNone = function () {
        vm.allowedDashboardIds = [];
        vm.saveSuccess = false;
    };

    // ── Validación para habilitar el botón Guardar ───────────────────────────
    vm.canSave = function () {
        if (!vm.selectedUser) return false;
        if (vm.saving || vm.loadingAttrs || vm.loadingInit) return false;
        if (vm.accessMode === 'restricted' && vm.allowedDashboardIds.length === 0) return false;
        return true;
    };

    // ── Guardar atributos en el usuario ──────────────────────────────────────
    vm.save = function () {
        if (!vm.canSave()) return;
        vm.saving = true;
        vm.saveSuccess = false;

        let userEntityId = { id: vm.selectedUser.id, entityType: 'USER' };

        let attributes = [
            { key: 'dashboardAccess', value: vm.accessMode }
        ];

        if (vm.accessMode === 'restricted') {
            // Guardamos como JSON string para compatibilidad con el widget Gallery
            attributes.push({
                key: 'allowedDashboards',
                value: (vm.allowedDashboardIds)
            });
        }

        attributeService.saveEntityAttributes(userEntityId, 'SERVER_SCOPE', attributes).subscribe(
            function () {
                vm.saving = false;
                vm.saveSuccess = true;
                widgetContext.showSuccessToast(
                    'Acceso guardado para ' + vm.selectedUser.name
                );
                safeApply();
            },
            function (err) {
                vm.saving = false;
                widgetContext.showErrorToast(
                    'Error al guardar: ' + (err.message || JSON.stringify(err))
                );
                safeApply();
            }
        );
    };

    // ── Cerrar dialog ────────────────────────────────────────────────────────
    vm.cancel = function () {
        vm.dialogRef.close(null);
    };

    // ── Helper: trigger change detection fuera de zona Angular ──────────────
    function safeApply() {
        try {
            widgetContext.$scope.$applyAsync();
        } catch (e) {
            // Ignorar si ya hay un digest en curso
        }
    }
}
